  async function createWorkspaceFromInputs() {
    const modal = app.modal?.type === 'source' ? app.modal : {};
    const appendWs = modal.appendWsId ? getWorkspace(modal.appendWsId) : null;
    const repoInput = $('source-repo')?.value?.trim() || '';
    const parsedRepo = parseGitHubRepoSpec(repoInput);
    const refInput = $('source-ref')?.value?.trim() || '';
    const rootPaths = parseRootPaths($('source-root')?.value || '.topics');
    const urls = ($('source-urls')?.value || '').split(/\n+/).map((s) => s.trim()).filter(Boolean);
    const inputFiles = Array.from($('source-files')?.files || []);
    const stagedFiles = [
      ...inputFiles,
      ...Array.from(modal.droppedFiles || []),
      ...Array.from(modal.pastedFiles || [])
    ];

    const label = appendWs
      ? appendWs.label
      : ($('source-label')?.value?.trim() || (parsedRepo ? `${parsedRepo.repo} · discovery` : 'Local lineage workspace'));

    const note = parsedRepo
      ? 'GitHub repository discovery workspace.'
      : (urls.length ? 'User-provided trace links.' : 'Local/pasted/uploaded lineage material.');
    const ws = appendWs || createWorkspace(label, note);

    app.modal = null;
    app.activeWorkspaceId = ws.id;
    focusWorkspaceWindow(ws.id);
    render();

    if (parsedRepo) {
      await discoverGitHubRepoIntoWorkspace(ws, {
        repo: parsedRepo.repo,
        ref: refInput || parsedRepo.ref || '',
        rootPaths: rootPaths.length ? rootPaths : parseRootPaths(parsedRepo.rootPath || '.topics')
      });
    }
    if (urls.length) await loadUrlsIntoWorkspace(ws, urls);
    if (stagedFiles.length) await readUploadedFilesIntoWorkspace(ws, stagedFiles);
    if (!parsedRepo && !urls.length && !stagedFiles.length && !appendWs) toast('Created empty workspace. Add traces by creating leaves or importing files later.', 'warn');

    computeWorkspaceIndex(ws);
    app.activeWorkspaceId = ws.id;
    focusWorkspaceWindow(ws.id);
    updateUrlState();
    render();
  }




  // ===== v6.37 restore search/filter event binding after v6.36 intake override =====
  // v6.36 replaced the final bindEvents layer and accidentally stopped binding
  // discovery search, lineage search, and filter controls. Keep the source
  // drop/paste additions, but reattach all viewer input handlers.

  function bindEvents(root) {
    root.querySelectorAll('[data-action]').forEach((el) => {
      el.addEventListener('click', onActionV645);
    });

    root.querySelectorAll('input[data-field], textarea[data-field], select[data-field]').forEach((el) => {
      el.addEventListener('input', onModalField);
      el.addEventListener('change', onModalField);
    });

    root.querySelectorAll('textarea[data-subfield]').forEach((el) => {
      el.addEventListener('input', onModalSubField);
    });

    root.querySelectorAll('.search-box input[data-mode], input[data-search-mode]').forEach((el) => {
      el.addEventListener('input', onSearchInput);
    });

    root.querySelectorAll('select[data-action="set-discovery-filter"], select.discovery-filter-select, select[data-filter-mode]').forEach((el) => {
      el.addEventListener('change', (event) => {
        const ws = getWorkspace(event.currentTarget.dataset.ws);
        if (!ws) return;
        ws.discoveryFilterSchema = event.currentTarget.value || event.currentTarget.dataset.filter || 'all';
        ws.filterSchema = ws.discoveryFilterSchema;
        setRouteState('replace');
        render();
      });
    });

    bindSourceDropzone(root);

    if (!app.sourcePasteBound) {
      document.addEventListener('paste', handleSourcePaste);
      app.sourcePasteBound = true;
    }
  }

  function onSearchInput(event) {
    const input = event.currentTarget;
    const ws = getWorkspace(input.dataset.ws);
    if (!ws) return;
    const mode = input.dataset.mode || input.dataset.searchMode || 'discovery';
    const value = input.value || '';

    if (mode === 'lineage') ws.lineageSearch = value;
    else ws.discoverySearch = value;

    app.searchTimers = app.searchTimers || {};
    if (app.searchTimers[ws.id]) clearTimeout(app.searchTimers[ws.id]);
    app.searchTimers[ws.id] = setTimeout(() => {
      setRouteState('replace');
      render();
    }, 160);
  }




  // ===== v6.38 robust delegated search/filter handlers =====
  // Previous patch still depended on exact selectors. Use event delegation so
  // future render-layer overrides do not break discovery/lineage search again.

  function eventTargetWorkspace(target) {
    const wsId = target?.dataset?.ws || target?.closest?.('[data-ws]')?.dataset?.ws || '';
    return getWorkspace(wsId);
  }

  function targetLooksSearchInput(target) {
    if (!target || target.tagName !== 'INPUT') return false;
    const placeholder = String(target.getAttribute('placeholder') || '').toLowerCase();
    return Boolean(target.dataset.mode || target.dataset.searchMode || target.closest?.('.search-box') || placeholder.includes('search discovery') || placeholder.includes('search lineage'));
  }

  function targetSearchMode(target) {
    const placeholder = String(target.getAttribute('placeholder') || '').toLowerCase();
    if (target.dataset.mode) return target.dataset.mode;
    if (target.dataset.searchMode) return target.dataset.searchMode;
    if (placeholder.includes('lineage')) return 'lineage';
    return 'discovery';
  }

  function applySearchInput(target) {
    const ws = eventTargetWorkspace(target);
    if (!ws) return false;

    const mode = targetSearchMode(target);
    if (mode === 'lineage') ws.lineageSearch = target.value || '';
    else ws.discoverySearch = target.value || '';

    app.searchTimers = app.searchTimers || {};
    const key = `${ws.id}:${mode}`;
    if (app.searchTimers[key]) clearTimeout(app.searchTimers[key]);
    app.searchTimers[key] = setTimeout(() => {
      setRouteState('replace');
      render();
    }, 120);

    return true;
  }

  function targetLooksDiscoveryFilter(target) {
    if (!target || target.tagName !== 'SELECT') return false;
    const action = target.dataset.action || '';
    return action === 'set-discovery-filter'
      || target.classList.contains('discovery-filter-select')
      || Boolean(target.dataset.filterMode)
      || target.closest?.('.filter-select-wrap');
  }

  function applyDiscoveryFilter(target) {
    const ws = eventTargetWorkspace(target);
    if (!ws) return false;
    ws.discoveryFilterSchema = target.value || target.dataset.filter || 'all';
    ws.filterSchema = ws.discoveryFilterSchema;
    setRouteState('replace');
    render();
    return true;
  }

  function bindEvents(root) {
    root.querySelectorAll('[data-action]').forEach((el) => {
      el.addEventListener('click', onActionV645);
    });

    root.querySelectorAll('input[data-field], textarea[data-field], select[data-field]').forEach((el) => {
      el.addEventListener('input', onModalField);
      el.addEventListener('change', onModalField);
    });

    root.querySelectorAll('textarea[data-subfield]').forEach((el) => {
      el.addEventListener('input', onModalSubField);
    });

    bindSourceDropzone(root);

    if (!app.delegatedViewerInputBound) {
      document.addEventListener('input', (event) => {
        const target = event.target;
        if (targetLooksSearchInput(target)) {
          applySearchInput(target);
        }
      });

      document.addEventListener('change', (event) => {
        const target = event.target;
        if (targetLooksDiscoveryFilter(target)) {
          applyDiscoveryFilter(target);
        }
      });

      app.delegatedViewerInputBound = true;
    }

    if (!app.sourcePasteBound) {
      document.addEventListener('paste', handleSourcePaste);
      app.sourcePasteBound = true;
    }
  }




