    if (typeof bindSourceDropzone === 'function') bindSourceDropzone(root);

    if (!app.sourcePasteBound && typeof handleSourcePaste === 'function') {
      document.addEventListener('paste', handleSourcePaste);
      app.sourcePasteBound = true;
    }
