  async function buildCurrentLensConfigMarkdown() {
    const cfg = app.viewerIdentity || {};
    const state = viewerStateForExport();
    const displayName = cfg.displayName || cfg.heading || 'Current Tiinex View';
    const descriptors = app.workspaces.map((ws, index) => workspaceExportDescriptor(ws, index, state.sources));
    const omitted = descriptors.filter((item) => !item.shareable || item.localOnlyItems);
    const subtitles = uniqueNonEmptyV676((viewerSubtitlePool?.() || []).map(subtitleForExportV676));
    const css = String(cfg.customCss || '').trim();

    const identityLines = linesOrEmptyV676([
      configLineV676('Label', cfg.label),
      configLineV676('Home', cfg.home, 'https://github.com/Tiinex'),
      configLineV676('Icon', cfg.icon),
      configLineV676('Accent', cfg.accent),
      configLineV676('Theme', cfg.theme)
    ]);

    const emptyStageLines = linesOrEmptyV676(subtitles.map((item) => `- Subtitle: ${item}`));
    const discovery = String(cfg.configDiscoveryMarkdown || '').trim();
    const workspaceEntrypoints = workspaceEntrypointsMarkdownV676(descriptors);
    const machineState = machineStateForExportV676(descriptors);

    const bodySections = [
      sectionBlockV676('Viewer Identity', identityLines),
      sectionBlockV676('Empty Stage', emptyStageLines),
      sectionBlockV676('Workspace Discovery', discovery),
      sectionBlockV676('Workspace Entrypoints', workspaceEntrypoints),
      css ? sectionBlockV676('Custom CSS', `\`\`\`css\n${css}\n\`\`\``) : '',
      machineState ? sectionBlockV676('Machine State', `\`\`\`json\n${JSON.stringify(machineState, null, 2)}\n\`\`\``) : ''
    ].filter(Boolean).join('\n\n');

    const summary = omitted.length
      ? `Portable workspace export for ${displayName}; local-only material is omitted.`
      : `Portable workspace export for ${displayName}.`;

    const markdown = `# Continuity Context

- Envelope Schema: [tiinex.root.v1](${TIINEX_ROOT_SCHEMA_URL_V674})
- Current
  - Current Schema: [tiinex.workspace.v1](.topics/.schemas/tiinex.workspace.v1.schema.md)
  - Created At: ${continuityTimestampV674()}
  - Why: Captures the current Tiinex viewer lens as a portable markdown entrypoint.
  - Summary: ${summary}

---

# ${displayName}

${bodySections}
`;

    return appendContinuityIntegrityV674(markdown, 'this exported config');
  }




  // ===== v6.77 workspace-provided Help lightbox =====
