    const match = raw.match(/(?:^|\/)(assets\/[^?#]+)/i);
    if (match) return match[1];
    const file = raw.split(/[?#]/)[0].split('/').filter(Boolean).pop();
    if (file && /\.(png|jpe?g|webp|gif|svg)$/i.test(file)) return `assets/${file}`;
    return '';
