  function parseViewerConfigMarkdown(markdown, configUrl) {
    const out = {};
    const text = normalizeMarkdownV676(markdown || '');
    const h1 = firstBodyH1AfterEnvelopeV676(text);
    if (h1) {
      out.heading = h1;
      out.displayName = h1;
    }

    const identity = sectionKeyValueMapV676(markdownSectionContentV676(text, 'Viewer Identity', 2));
    const legacyTop = legacyTopLevelConfigMapV678(text);

    function readIdentityField(names) {
      return firstKvV676(identity, names) || firstKvV676(legacyTop, names);
    }

    const legacyDisplay = readIdentityField(['Display Name', 'Display-name']);
    if (!out.displayName && legacyDisplay) out.displayName = legacyDisplay;

    const label = readIdentityField(['Label']);
    if (label) out.label = label;
    const icon = readIdentityField(['Icon', 'Logo', 'Mark']);
    if (icon) {
      out.iconRaw = icon;
      out.icon = workspaceAssetUrlV683(icon, configUrl);
    }
    const home = readIdentityField(['Home', 'Href', 'Link', 'URL']);
    if (home) out.home = markdownConfigValue(home, configUrl);
    const accent = readIdentityField(['Accent']);
    if (accent) out.accent = accent;
    const theme = readIdentityField(['Theme']);
    if (theme) out.theme = theme;
    const css = readIdentityField(['CSS', 'Stylesheet', 'Style']);
    if (css) out.cssUrl = workspaceAssetUrlV683(css, configUrl);

    Object.assign(out, parseEmptyStageV676(text));
    out.configDiscoveryMarkdown = parseConfigDiscoveryV676(text);
    const help = helpMarkdownFromConfigV677(text);
    if (help) out.helpMarkdown = help;

    const viewerState = extractViewerStateJson(text);
    const machineState = extractMachineStateJsonV676(text);
    if (viewerState?.__parseError) out.viewerStateError = viewerState.__parseError;
    else if (viewerState) out.viewerState = viewerState;
    else {
      const generated = parseWorkspaceEntrypointsV676(text, configUrl, machineState && !machineState.__parseError ? machineState : null);
      if (generated) out.viewerState = generated;
    }
    if (machineState?.__parseError) out.machineStateError = machineState.__parseError;
    else if (machineState) out.machineState = machineState;

    out.customCss = extractViewerCustomCss(text);
    return out;
  }

