      computeWorkspaceIndex(ws);
      const loaded = loadedSchemaNodeForCandidatesV694(ws, candidate.candidates, node.currentSchemaText || node.currentSchema)
        || Array.from(ws.nodeById.values()).find((item) => item.rawUrl === candidate.rawUrl);
      if (loaded) return openSchemaNodeV694(ws, loaded, 'reading contract');
