  // ===== v6.149 contextual Add/Edit markdown studio =====
  function markdownPreviewInlineV6149(text) {
    return escapeHtml(text || '')
      .replace(/`([^`]+)`/g, '<code>$1</code>')
      .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
      .replace(/\*([^*]+)\*/g, '<em>$1</em>')
      .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>');
  }

  function renderSimpleMarkdownPreviewV6149(text) {
    const lines = String(text || '').replace(/\r\n?/g, '\n').split('\n');
    const html = [];
    let inCode = false;
    let listOpen = false;

    const closeList = () => {
      if (listOpen) {
        html.push('</ul>');
        listOpen = false;
      }
    };

    for (const raw of lines) {
      const line = raw.trimEnd();
      if (/^```/.test(line.trim())) {
        closeList();
        if (!inCode) {
          html.push('<pre><code>');
          inCode = true;
        } else {
          html.push('</code></pre>');
          inCode = false;
        }
        continue;
      }
      if (inCode) {
        html.push(escapeHtml(raw) + '\n');
        continue;
      }
      if (!line.trim()) {
        closeList();
        html.push('<br>');
        continue;
      }

      const heading = line.match(/^(#{1,6})\s+(.*)$/);
      if (heading) {
        closeList();
        const level = Math.min(6, heading[1].length);
        html.push(`<h${level}>${markdownPreviewInlineV6149(heading[2])}</h${level}>`);
        continue;
      }

      if (/^---+$/.test(line.trim())) {
        closeList();
        html.push('<hr>');
        continue;
      }

      const bullet = line.match(/^\s*[-*]\s+(.*)$/);
      if (bullet) {
        if (!listOpen) {
          html.push('<ul>');
          listOpen = true;
        }
        html.push(`<li>${markdownPreviewInlineV6149(bullet[1])}</li>`);
        continue;
      }

      const quote = line.match(/^>\s?(.*)$/);
      if (quote) {
        closeList();
        html.push(`<blockquote>${markdownPreviewInlineV6149(quote[1])}</blockquote>`);
        continue;
      }

      closeList();
      html.push(`<p>${markdownPreviewInlineV6149(line)}</p>`);
    }
    closeList();
    if (inCode) html.push('</code></pre>');
    return html.join('\n');
  }

